// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/* 
 * A single event in the streaming inference output stream.
 *
 * Text tokens arrive as `Text`.  Raw media (uncompressed pixels, PCM audio,
 * embeddings) arrives as the other variants — Vec<u8> maps to Swift's
 * Foundation.Data and Vec<f32> maps to [Float] with zero manual conversion.
 *
 * Each `VideoFrame` carries a monotonic `timestamp_ns` so the Swift export
 * pipeline (AVAssetWriter → ProRes .mov) can reconstruct a deterministic
 * timeline that NLEs like DaVinci Resolve or Final Cut Pro accept without
 * resampling or drift correction.
 */

public enum StreamEvent {
    case text(token: String)
    /**
     * Raw uncompressed BGRA 8-bit pixel array for direct CVPixelBuffer wrapping.
     */
    case imageFrame(pixelBytes: Data, width: UInt32, height: UInt32)
    /**
     * Raw uncompressed BGRA 8-bit pixel array with high-precision timestamp
     * for ProRes video track assembly.
     */
    case videoFrame(pixelBytes: Data, width: UInt32, height: UInt32, timestampNs: UInt64)
    /**
     * Raw Linear PCM audio bytes (32-bit float or 16-bit int) for Core Audio
     * CMSampleBuffer ingestion.  `sample_rate` in Hz, `channels` = 1 (mono)
     * or 2 (stereo).
     */
    case audioChunk(pcmBytes: Data, sampleRate: UInt32, channels: UInt32)
    /**
     * Dense vector embedding from the model.  Used for similarity search,
     * clustering, or conditioning downstream generators.
     */
    case embedding(values: [Float])
}

public struct FfiConverterTypeStreamEvent: FfiConverterRustBuffer {
    typealias SwiftType = StreamEvent

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> StreamEvent {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        case 1: return try .text(token: FfiConverterString.read(from: &buf))

        case 2: return try .imageFrame(pixelBytes: FfiConverterData.read(from: &buf), width: FfiConverterUInt32.read(from: &buf), height: FfiConverterUInt32.read(from: &buf))

        case 3: return try .videoFrame(pixelBytes: FfiConverterData.read(from: &buf), width: FfiConverterUInt32.read(from: &buf), height: FfiConverterUInt32.read(from: &buf), timestampNs: FfiConverterUInt64.read(from: &buf))

        case 4: return try .audioChunk(pcmBytes: FfiConverterData.read(from: &buf), sampleRate: FfiConverterUInt32.read(from: &buf), channels: FfiConverterUInt32.read(from: &buf))

        case 5: return try .embedding(values: FfiConverterSequenceFloat.read(from: &buf))

        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: StreamEvent, into buf: inout [UInt8]) {
        switch value {
        case let .text(token):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(token, into: &buf)

        case let .imageFrame(pixelBytes, width, height):
            writeInt(&buf, Int32(2))
            FfiConverterData.write(pixelBytes, into: &buf)
            FfiConverterUInt32.write(width, into: &buf)
            FfiConverterUInt32.write(height, into: &buf)

        case let .videoFrame(pixelBytes, width, height, timestampNs):
            writeInt(&buf, Int32(3))
            FfiConverterData.write(pixelBytes, into: &buf)
            FfiConverterUInt32.write(width, into: &buf)
            FfiConverterUInt32.write(height, into: &buf)
            FfiConverterUInt64.write(timestampNs, into: &buf)

        case let .audioChunk(pcmBytes, sampleRate, channels):
            writeInt(&buf, Int32(4))
            FfiConverterData.write(pcmBytes, into: &buf)
            FfiConverterUInt32.write(sampleRate, into: &buf)
            FfiConverterUInt32.write(channels, into: &buf)

        case let .embedding(values):
            writeInt(&buf, Int32(5))
            FfiConverterSequenceFloat.write(values, into: &buf)
        }
    }
}

